CREATE TABLE rt_current( 
   ID          VARCHAR(30) NOT NULL PRIMARY KEY
  ,ticker      VARCHAR(10) NOT NULL
  ,name        VARCHAR(50) NOT NULL
  ,Date        DATE  NOT NULL
  ,close_value NUMERIC(30,15) NOT NULL
  ,sector      VARCHAR(50) NOT NULL
  ,industry    VARCHAR(50) NOT NULL
);

